/**
* Script para crear tours europeos con traducciones completas.
*
* Ciudades cubiertas (top visitadas 2023-2024 según Euromonitor / Statista):
*   París, Roma, Barcelona, Madrid, Ámsterdam, Berlín, Viena, Praga,
*   Lisboa, Budapest, Florencia, Venecia, Dubrovnik, Cracovia, Atenas, Dublín.
*
* Uso:
*   drush php:script create_european_tours.php
*
* Requiere:
*   - content type 'tour'      con los fields del script original
*   - content type 'tour_step' con los fields del script original
*   - Módulo content_translation habilitado
*   - Vocabularios 'countries' y 'cities' ya importados
*/

// ===========================================================================
// ⚙️  CONFIGURACIÓN
// ===========================================================================
$tour_owner_uid = 1; // ← UID del autor

// Idiomas disponibles (deben estar habilitados en /admin/config/regional/language)
$languages = ['es', 'fr', 'de', 'it'];
// ===========================================================================

use Drupal\node\Entity\Node;
use Drupal\user\Entity\User;

$node_storage  = \Drupal::entityTypeManager()->getStorage('node');
$term_storage  = \Drupal::entityTypeManager()->getStorage('taxonomy_term');

$owner = User::load($tour_owner_uid);
if (!$owner) {
echo "❌ Error: No existe ningún usuario con UID {$tour_owner_uid}.\n";
exit(1);
}
echo "👤 Autor: " . $owner->getDisplayName() . " (UID: {$tour_owner_uid})\n\n";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function get_term_by_name($vid, $name) {
$terms = \Drupal::entityTypeManager()
->getStorage('taxonomy_term')
->loadByProperties(['vid' => $vid, 'name' => $name]);
return !empty($terms) ? reset($terms) : NULL;
}

function point($lat, $lng) {
return 'POINT(' . $lng . ' ' . $lat . ')';
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function get_term_p2($vid, $name) {
  $terms = \Drupal::entityTypeManager()
    ->getStorage('taxonomy_term')
    ->loadByProperties(['vid' => $vid, 'name' => $name]);
  return !empty($terms) ? reset($terms) : NULL;
}

function point_p2($lat, $lng) {
  return 'POINT(' . $lng . ' ' . $lat . ')';
}

/**
* Adds a translation to a node if the language is enabled on the site.
*/
function add_node_translation(Node $node, string $langcode, array $fields): void {
$lang_manager = \Drupal::languageManager();
if (!$lang_manager->getLanguage($langcode)) {
echo "      ⚠️  Idioma '{$langcode}' no habilitado, saltando traducción.\n";
return;
}
if ($node->hasTranslation($langcode)) {
$translation = $node->getTranslation($langcode);
} else {
$translation = $node->addTranslation($langcode, $fields);
}
foreach ($fields as $field => $value) {
$translation->set($field, $value);
}
$translation->save();
}

