// ===========================================================================
// CREATE TOURS AND STEPS
// ===========================================================================

foreach ($tours as $tour_data) {

echo "📍 Creating tour: {$tour_data['title']}\n";

// Check if already exists
$existing = $node_storage->loadByProperties([
'type'  => 'tour',
'title' => $tour_data['title'],
]);

if (!empty($existing)) {
echo "⏭️  Already exists, skipping.\n\n";
continue;
}

// Load taxonomy terms
$country_term = get_term_p2('countries', $tour_data['country']);
if (!$country_term) {
echo "⚠️  Country '{$tour_data['country']}' not found in taxonomy. Run import_countries.php first.\n\n";
continue;
}

$city_term = get_term_p2('cities', $tour_data['city']);
if (!$city_term) {
echo "⚠️  City '{$tour_data['city']}' not found in taxonomy. Run import_cities.php first.\n\n";
continue;
}

// Create the tour node
$tour = Node::create([
'type'                 => 'tour',
'title'                => $tour_data['title'],
'status'               => 1,
'uid'                  => $tour_owner_uid,
'langcode'             => 'en',
'field_description'    => [
'value'  => $tour_data['description'],
'format' => 'basic_html',
],
'field_duration'       => $tour_data['duration'],
'field_country'        => [['target_id' => $country_term->id()]],
'field_city'           => [['target_id' => $city_term->id()]],
'field_average_rate'   => '0.00',
'field_donation_count' => 0,
'field_donation_total' => '0.00',
'field_revenue_split'  => 'professional',
'field_location'       => point_p2($tour_data['location']['lat'], $tour_data['location']['lng']),
]);

$tour->save();
echo "   ✅ Tour created — NID: " . $tour->id() . " | UUID: " . $tour->uuid() . "\n";

// Create tour steps
foreach ($tour_data['steps'] as $step_data) {
$step = Node::create([
'type'                    => 'tour_step',
'title'                   => $step_data['title'],
'status'                  => 1,
'uid'                     => $tour_owner_uid,
'langcode'                => 'en',
'field_description'       => [
'value'  => $step_data['description'],
'format' => 'basic_html',
],
'field_order'             => $step_data['order'],
'field_tour'              => [['target_id' => $tour->id()]],
'field_total_completed'   => 0,
'field_location'          => point_p2($step_data['location']['lat'], $step_data['location']['lng']),
]);
$step->save();
echo "      📌 Step {$step_data['order']}: {$step_data['title']} (NID: " . $step->id() . ")\n";
}

echo "\n";
}

echo "========================================\n";
echo "✅ All tours created successfully.\n";
echo "========================================\n\n";
echo "Tour UUIDs created in this run:\n\n";

$all_tours = $node_storage->loadByProperties(['type' => 'tour']);
foreach ($all_tours as $t) {
echo "  " . $t->getTitle() . "\n";
echo "  UUID: " . $t->uuid() . "\n\n";
}
